import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
// import MasterLayout from './layouts/admin/MasterLayout';

import Dashboard from './assests/admin/admin/Dashboard';
import Profile from './assests/admin/admin/Profile';


function App()
{
  return (
    <div className="App">
      <Router>
        <Routes>
          {/* <Route path="/admin/dashboard" element={<MasterLayout />} /> */}

          <Route exact path="http://localhost:3000/admin/dashboard" element={<Dashboard />} />
          <Route exact path="../admin/profile" element={<Profile />} />

        </Routes>
      </Router>
    </div>
  );
}

export default App;
